    try {
      const response = await auditLogService.getById(log.id);
      if (response.success) {
        setSelectedLog(response.data);
        setShowDetailModal(true);
      }
    } catch (error) {
      toast.error("Lỗi khi tải chi tiết log");
      console.error(error);
    }
  };

