import { useCallback, useEffect, useState } from "react";
import toast from "react-hot-toast";
import { Link } from "react-router-dom";
import { ArrowLeft, Check, Plus, Trash2, X } from "lucide-react";
import * as bookingApi from "@/apis/bookingService";
import * as ruleApi from "@/apis/bookingAutoRuleApi";
import { BUSINESS_ROUTES } from "@/constants/routes";
import { BOOKING_STATUS } from "@/constants/constants";
import {
  TIME_SLOT_KEYS,
  TIME_SLOT_LABELS,
} from "@/constants/bookingSchedule";
import { toastApiErrorIfNeeded } from "@/utils/businessApiErrorUx";
import {
  PageHeader,
  SectionCard,
  EmptyState,
  formatVND,
  formatDate,
} from "@/components/business/DashboardWidgets";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Checkbox } from "@/components/ui/checkbox";
import { Switch } from "@/components/ui/switch";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/Tabs";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import { Label } from "@/components/ui/Label";
import { cn } from "@/lib/utils";
import BulkActionBar from "@/components/business/BulkActionBar";

const SLOT_OPTIONS = [
  TIME_SLOT_KEYS.MORNING,
  TIME_SLOT_KEYS.NOON,
  TIME_SLOT_KEYS.AFTERNOON,
  TIME_SLOT_KEYS.EVENING,
];

const BookingQuickProcessPage = () => {
  const [tab, setTab] = useState("pending");
  const [pending, setPending] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState([]);
  const [busyId, setBusyId] = useState(null);
  const [rules, setRules] = useState([]);
  const [rulesLoading, setRulesLoading] = useState(false);
  const [ruleOpen, setRuleOpen] = useState(false);
  const [ruleForm, setRuleForm] = useState({
    priority: 0,
    timeSlots: [],
    minQuantity: "",
    maxQuantity: "",
    isActive: true,
  });

  const loadPending = useCallback(async () => {
    setLoading(true);
    try {
      const res = await bookingApi.getAll({
        status: BOOKING_STATUS.PENDING,
        limit: 100,
        page: 1,
      });
      if (res?.success) setPending(res.data || []);
      else toast.error(res?.message || "Không tải được danh sách");
    } catch (e) {
      toastApiErrorIfNeeded(e);
    } finally {
      setLoading(false);
    }
  }, []);

  const loadRules = useCallback(async () => {
    setRulesLoading(true);
    try {
      const res = await ruleApi.list();
      if (res?.success) setRules(res.data || []);
      else toast.error(res?.message || "Không tải rule");
    } catch (e) {
      toastApiErrorIfNeeded(e);
    } finally {
      setRulesLoading(false);
    }
  }, []);

  useEffect(() => {
    loadPending();
  }, [loadPending]);

  useEffect(() => {
    if (tab === "rules") loadRules();
  }, [tab, loadRules]);

  const toggleSelect = (id) => {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id],
    );
  };

  const selectAll = (checked) => {
    if (checked) setSelected(pending.map((b) => b.id));
    else setSelected([]);
  };

  const handleQuickApprove = async (id) => {
    setBusyId(id);
    try {
      const res = await bookingApi.quickApprove(id);
      if (res?.success) {
        toast.success("Đã duyệt");
        await loadPending();
      } else toast.error(res?.message || "Lỗi");
    } catch (e) {
      toastApiErrorIfNeeded(e);
    } finally {
      setBusyId(null);
    }
  };

  const handleQuickReject = async (id) => {
    const reason = window.prompt("Lý do từ chối (tùy chọn):") || "";
    setBusyId(id);
    try {
      const res = await bookingApi.quickReject(id, reason || undefined);
      if (res?.success) {
        toast.success("Đã từ chối");
        await loadPending();
      } else toast.error(res?.message || "Lỗi");
    } catch (e) {
      toastApiErrorIfNeeded(e);
    } finally {
      setBusyId(null);
    }
  };

  const bulkApprove = async () => {
    for (const id of selected) {
      try {
        await bookingApi.quickApprove(id);
      } catch {
        /* toast below */
      }
    }
    toast.success("Đã xử lý hàng loạt (một số có thể lỗi nếu trùng slot)");
    setSelected([]);
    await loadPending();
  };

  const bulkReject = async () => {
    const reason = window.prompt("Lý do từ chối chung:") || "";
    for (const id of selected) {
      try {
        await bookingApi.quickReject(id, reason || undefined);
      } catch {
        /* ignore */
      }
    }
    toast.success("Đã từ chối hàng loạt");
    setSelected([]);
    await loadPending();
  };

  const submitRule = async () => {
    const conditions = {};
    if (ruleForm.timeSlots.length)
      conditions.timeSlots = ruleForm.timeSlots;
    if (ruleForm.minQuantity !== "")
      conditions.minQuantity = parseInt(ruleForm.minQuantity, 10);
    if (ruleForm.maxQuantity !== "")
      conditions.maxQuantity = parseInt(ruleForm.maxQuantity, 10);

    if (
      !conditions.timeSlots?.length &&
      conditions.minQuantity == null &&
      conditions.maxQuantity == null
    ) {
      toast.error("Chọn ít nhất một khung giờ hoặc điều kiện số lượng");
      return;
    }

    try {
      const res = await ruleApi.create({
        priority: ruleForm.priority,
        conditions,
        isActive: ruleForm.isActive,
      });
      if (res?.success) {
        toast.success("Đã tạo rule");
        setRuleOpen(false);
        setRuleForm({
          priority: 0,
          timeSlots: [],
          minQuantity: "",
          maxQuantity: "",
          isActive: true,
        });
        await loadRules();
      } else toast.error(res?.message || "Lỗi");
    } catch (e) {
      toastApiErrorIfNeeded(e);
    }
  };

  const toggleRuleActive = async (rule) => {
    try {
      const res = await ruleApi.update(rule.id, { isActive: !rule.isActive });
      if (res?.success) await loadRules();
    } catch (e) {
      toastApiErrorIfNeeded(e);
    }
  };

  const deleteRule = async (rule) => {
    if (!window.confirm("Vô hiệu hóa rule này?")) return;
    try {
      const res = await ruleApi.remove(rule.id);
      if (res?.success) await loadRules();
    } catch (e) {
      toastApiErrorIfNeeded(e);
    }
  };

  return (
    <div className="space-y-6 p-6 lg:p-8 min-h-screen">
      <Link
        to={BUSINESS_ROUTES.BOOKINGS}
        className="inline-flex items-center gap-2 text-sm font-medium text-muted-foreground hover:text-foreground"
      >
        <ArrowLeft className="h-4 w-4" />
        Danh sách đặt chỗ
      </Link>

      <PageHeader
        title="Xử lý đặt chỗ nhanh"
        subtitle="Duyệt / từ chối tức thì và cấu hình auto-duyệt theo rule"
      />

      <Tabs value={tab} onValueChange={setTab}>
        <TabsList>
          <TabsTrigger value="pending">Chờ xử lý</TabsTrigger>
          <TabsTrigger value="rules">Auto-duyệt</TabsTrigger>
        </TabsList>

        <TabsContent value="pending" className="mt-4 space-y-4">
          {selected.length > 0 && (
            <div className="sticky bottom-4 z-30 flex flex-wrap items-center gap-2 rounded-xl border border-border bg-card/95 p-3 shadow-md backdrop-blur">
              <span className="text-sm text-muted-foreground">
                Đã chọn {selected.length}
              </span>
              <Button size="sm" onClick={bulkApprove} className="gap-1">
                <Check className="h-4 w-4" />
                Duyệt đã chọn
              </Button>
              <Button
                size="sm"
                variant="outline"
                onClick={bulkReject}
                className="gap-1"
              >
                <X className="h-4 w-4" />
                Từ chối đã chọn
              </Button>
              <Button size="sm" variant="ghost" onClick={() => setSelected([])}>
                Bỏ chọn
              </Button>
            </div>
          )}

          {loading ? (
            <p className="text-sm text-muted-foreground">Đang tải…</p>
          ) : pending.length === 0 ? (
            <EmptyState message="Không có booking chờ xử lý" />
          ) : (
            <SectionCard>
              <div className="mb-3 flex items-center gap-2">
                <Checkbox
                  checked={
                    pending.length > 0 && selected.length === pending.length
                  }
                  onCheckedChange={selectAll}
                />
                <span className="text-xs text-muted-foreground">Chọn tất cả</span>
              </div>
              <div className="space-y-2">
                {pending.map((b) => (
                  <div
                    key={b.id}
                    className={cn(
                      "flex flex-wrap items-center gap-3 rounded-lg border border-border bg-card p-3",
                      selected.includes(b.id) && "ring-1 ring-primary/50",
                    )}
                  >
                    <Checkbox
                      checked={selected.includes(b.id)}
                      onCheckedChange={() => toggleSelect(b.id)}
                    />
                    <div className="min-w-0 flex-1">
                      <p className="font-medium">{b.guestName}</p>
                      <p className="text-xs text-muted-foreground">
                        {b.bookingCode} · {b.guestPhone} ·{" "}
                        {b.service?.name} · {formatDate(b.useDate)}{" "}
                        {b.useTime}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {formatVND(b.finalPrice)}
                      </p>
                    </div>
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        disabled={busyId === b.id}
                        onClick={() => handleQuickApprove(b.id)}
                      >
                        Duyệt
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        disabled={busyId === b.id}
                        onClick={() => handleQuickReject(b.id)}
                      >
                        Từ chối
                      </Button>
                      <Button size="sm" variant="ghost" asChild>
                        <Link to={BUSINESS_ROUTES.BOOKING_DETAIL(b.id)}>
                          Chi tiết
                        </Link>
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            </SectionCard>
          )}
        </TabsContent>

        <TabsContent value="rules" className="mt-4 space-y-4">
          <div className="flex justify-end">
            <Button onClick={() => setRuleOpen(true)} className="gap-1">
              <Plus className="h-4 w-4" />
              Thêm rule
            </Button>
          </div>

          {rulesLoading ? (
            <p className="text-sm text-muted-foreground">Đang tải rule…</p>
          ) : rules.length === 0 ? (
            <EmptyState message="Chưa có rule auto-duyệt" />
          ) : (
            <SectionCard>
              <div className="space-y-3">
                {rules.map((r) => (
                  <div
                    key={r.id}
                    className="flex flex-wrap items-center justify-between gap-3 rounded-lg border p-3"
                  >
                    <div>
                      <p className="font-medium">{`Rule #${r.id} · priority ${r.priority}`}</p>
                      <p className="text-xs text-muted-foreground font-mono">
                        {JSON.stringify(r.conditions)}
                      </p>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="flex items-center gap-2">
                        <span className="text-xs">Kích hoạt</span>
                        <Switch
                          checked={r.isActive}
                          onCheckedChange={() => toggleRuleActive(r)}
                        />
                      </div>
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => deleteRule(r)}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            </SectionCard>
          )}
        </TabsContent>
      </Tabs>

      <Dialog open={ruleOpen} onOpenChange={setRuleOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Rule auto-duyệt</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div>
              <Label>Độ ưu tiên (cao hơn xử lý trước)</Label>
              <Input
                type="number"
                value={ruleForm.priority}
                onChange={(e) =>
                  setRuleForm((f) => ({
                    ...f,
                    priority: parseInt(e.target.value, 10) || 0,
                  }))
                }
              />
            </div>
            <div className="space-y-2">
              <Label>Khung giờ áp dụng</Label>
              {SLOT_OPTIONS.map((slot) => (
                <label
                  key={slot}
                  className="flex items-center gap-2 text-sm"
                >
                  <Checkbox
                    checked={ruleForm.timeSlots.includes(slot)}
                    onCheckedChange={(ck) => {
                      setRuleForm((f) => ({
                        ...f,
                        timeSlots: ck
                          ? [...f.timeSlots, slot]
                          : f.timeSlots.filter((s) => s !== slot),
                      }));
                    }}
                  />
                  {TIME_SLOT_LABELS[slot]}
                </label>
              ))}
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>min số lượng (tùy chọn)</Label>
                <Input
                  value={ruleForm.minQuantity}
                  onChange={(e) =>
                    setRuleForm((f) => ({ ...f, minQuantity: e.target.value }))
                  }
                />
              </div>
              <div>
                <Label>max số lượng (tùy chọn)</Label>
                <Input
                  value={ruleForm.maxQuantity}
                  onChange={(e) =>
                    setRuleForm((f) => ({ ...f, maxQuantity: e.target.value }))
                  }
                />
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Switch
                checked={ruleForm.isActive}
                onCheckedChange={(v) =>
                  setRuleForm((f) => ({ ...f, isActive: v }))
                }
              />
              <span className="text-sm">Kích hoạt</span>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setRuleOpen(false)}>
              Hủy
            </Button>
            <Button onClick={submitRule}>Lưu</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default BookingQuickProcessPage;

import {
  useEffect,
  useState,
  useCallback,
  useMemo,
  useTransition,
} from "react";
import toast from "react-hot-toast";
import { toastApiErrorIfNeeded } from "@/utils/businessApiErrorUx";
import {
  Star,
  Search,
  MessageSquare,
  Send,
  X,
  MessagesSquare,
  Pencil,
  Trash2,
  Eye,
  EyeOff,
  Loader2,
} from "lucide-react";
import api from "@/constants/api";
import { getMyPlaces } from "@/apis/businessApi";
import {
  SectionCard,
  PageHeader,
  EmptyState,
  DESIGN,
} from "@/components/business/DashboardWidgets";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/Tabs";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

const REVIEW_API = "/business/reviews";

// ─── Star Rating ──────────────────────────────────────────────────────────────

const StarRating = ({ rating, size = "sm" }) => {
  const sz = size === "lg" ? "h-5 w-5" : "h-3.5 w-3.5";
  return (
    <div className="flex gap-0.5">
      {[1, 2, 3, 4, 5].map((i) => (
        <Star
          key={i}
          className={`${sz} ${i <= rating ? "fill-yellow-400 text-yellow-400" : "text-muted-foreground/30"}`}
        />
      ))}
    </div>
  );
};

// ─── Review Card ──────────────────────────────────────────────────────────────

const ReviewCard = ({
  review,
  replyingTo,
  replyContent,
  editingReplyId,
  editContent,
  sending,
  actionLoadingByReply,
  onStartReply,
  onCancelReply,
  onContentChange,
  onSendReply,
  onStartEditReply,
  onCancelEditReply,
  onEditContentChange,
  onSaveEditReply,
  onDeleteReply,
  onModerateReply,
}) => {
  const formatDate = (date) =>
    date ? new Date(date).toLocaleDateString("vi-VN") : "";
  const hasReplied = review.replies?.length > 0;
  const isReplying = replyingTo === review.id;

  const getModerateReplyIcon = (reply) => {
    if (actionLoadingByReply[reply.id]) {
      return <Loader2 className="h-3.5 w-3.5 animate-spin" />;
    }
    if (reply.status === "hidden") {
      return <Eye className="h-3.5 w-3.5" />;
    }
    return <EyeOff className="h-3.5 w-3.5" />;
  };

  return (
    <div className={cn(DESIGN.card, "[content-visibility:auto] p-5 space-y-3")}>
      {/* Header */}
      <div className="flex items-start gap-3">
        <div className="h-9 w-9 rounded-full bg-muted flex items-center justify-center shrink-0 font-semibold text-sm text-muted-foreground">
          {(review.user?.profile?.fullName || "?")?.[0]?.toUpperCase()}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="font-semibold text-sm text-foreground">
              {review.user?.profile?.fullName || "Ẩn danh"}
            </span>
            <StarRating rating={review.rating} />
            {!hasReplied && (
              <Badge
                variant="outline"
                className="text-[10px] text-amber-600 border-amber-200 bg-amber-50"
              >
                Chưa phản hồi
              </Badge>
            )}
          </div>
          <p className="text-xs text-muted-foreground mt-0.5">
            {review.place?.name} · {formatDate(review.createdAt)}
          </p>
        </div>
      </div>

      {/* Content */}
      {review.title && (
        <p className="font-medium text-sm text-foreground">{review.title}</p>
      )}
      {review.content && (
        <p className="text-sm text-muted-foreground leading-relaxed">
          {review.content}
        </p>
      )}

      {/* Existing replies */}
      {hasReplied && (
        <div className="ml-6 pl-4 border-l-2 border-primary/30 space-y-3">
          {review.replies.map((reply) => (
            <div key={reply.id}>
              <div className="flex items-center justify-between gap-2">
                <div className="flex items-center gap-2">
                  <span className="text-xs font-semibold text-primary">
                    {reply.user?.profile?.fullName || "Doanh nghiệp"}
                  </span>
                  <span className="text-[10px] text-muted-foreground">
                    {formatDate(reply.createdAt)}
                  </span>
                  {reply.status === "hidden" && (
                    <Badge
                      variant="outline"
                      className="text-[10px] border-amber-300 text-amber-700 bg-amber-50"
                    >
                      Đã ẩn
                    </Badge>
                  )}
                </div>
                <div className="flex items-center gap-1">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-7 w-7 p-0"
                    onClick={() => onStartEditReply(reply)}
                    disabled={
                      !!actionLoadingByReply[reply.id] ||
                      editingReplyId === reply.id
                    }
                  >
                    <Pencil className="h-3.5 w-3.5" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-7 w-7 p-0"
                    onClick={() =>
                      onModerateReply(
                        reply.id,
                        reply.status === "hidden" ? "visible" : "hidden",
                      )
                    }
                    disabled={!!actionLoadingByReply[reply.id]}
                  >
                    {getModerateReplyIcon(reply)}
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-7 w-7 p-0 text-destructive hover:text-destructive"
                    onClick={() => onDeleteReply(reply.id)}
                    disabled={!!actionLoadingByReply[reply.id]}
                  >
                    <Trash2 className="h-3.5 w-3.5" />
                  </Button>
                </div>
              </div>

              {editingReplyId === reply.id ? (
                <div className="mt-1 flex gap-2 items-start">
                  <Textarea
                    value={editContent}
                    onChange={(e) => onEditContentChange(e.target.value)}
                    rows={2}
                    className="flex-1 text-xs"
                  />
                  <div className="flex flex-col gap-1">
                    <Button
                      size="sm"
                      className="h-8 w-8 p-0"
                      onClick={() => onSaveEditReply(reply.id)}
                      disabled={!!actionLoadingByReply[reply.id]}
                    >
                      {actionLoadingByReply[reply.id] ? (
                        <Loader2 className="h-3.5 w-3.5 animate-spin" />
                      ) : (
                        <Send className="h-3.5 w-3.5" />
                      )}
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      className="h-8 w-8 p-0"
                      onClick={onCancelEditReply}
                    >
                      <X className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
              ) : (
                <p className="text-xs text-muted-foreground mt-0.5 leading-relaxed">
                  {reply.content}
                </p>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Reply UI */}
      {isReplying ? (
        <div className="flex gap-2 items-start">
          <Textarea
            autoFocus
            placeholder="Nhập phản hồi..."
            value={replyContent}
            onChange={(e) => onContentChange(e.target.value)}
            rows={2}
            className="flex-1 text-sm"
          />
          <div className="flex flex-col gap-1">
            <Button
              size="sm"
              className="h-9 w-9 p-0"
              onClick={onSendReply}
              disabled={sending}
            >
              <Send className="h-3.5 w-3.5" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              className="h-9 w-9 p-0"
              onClick={onCancelReply}
            >
              <X className="h-3.5 w-3.5" />
            </Button>
          </div>
        </div>
      ) : (
        !hasReplied && (
          <Button
            variant="outline"
            size="sm"
            className="gap-1.5 h-8 text-xs"
            onClick={() => onStartReply(review.id)}
          >
            <MessageSquare className="h-3.5 w-3.5" />
            Phản hồi
          </Button>
        )
      )}
    </div>
  );
};

// ─── Rating Bar ───────────────────────────────────────────────────────────────

const RatingBar = ({ star, count, total }) => {
  const pct = total > 0 ? (count / total) * 100 : 0;
  return (
    <div className="flex items-center gap-3">
      <span className="text-xs text-muted-foreground w-8 shrink-0 text-right">
        {star} ★
      </span>
      <div className="flex-1 h-2 rounded-full bg-muted overflow-hidden">
        <div
          className="h-full bg-yellow-400 rounded-full transition-all duration-500"
          style={{ width: `${pct}%` }}
        />
      </div>
      <span className="text-xs text-muted-foreground w-6 shrink-0">
        {count}
      </span>
    </div>
  );
};

// ─── Main Page ────────────────────────────────────────────────────────────────

const ReviewListPage = () => {
  const [reviews, setReviews] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [places, setPlaces] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedPlaceId, setSelectedPlaceId] = useState("all");
  const [ratingFilter, setRatingFilter] = useState("0");
  const [tabFilter, setTabFilter] = useState("all");
  const [replyingTo, setReplyingTo] = useState(null);
  const [replyContent, setReplyContent] = useState("");
  const [sending, setSending] = useState(false);
  const [editingReplyId, setEditingReplyId] = useState(null);
  const [editContent, setEditContent] = useState("");
  const [actionLoadingByReply, setActionLoadingByReply] = useState({});
  const [isPendingTransition, startTransition] = useTransition();

  const loadReviews = useCallback(async () => {
    setLoading(true);
    try {
      const response = await api.get(REVIEW_API, {
        params: {
          search,
          placeId: selectedPlaceId !== "all" ? selectedPlaceId : undefined,
          rating: ratingFilter !== "0" ? ratingFilter : undefined,
          page: 1,
          limit: 50,
        },
      });
      setReviews(response.data || []);
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể tải danh sách đánh giá");
    } finally {
      setLoading(false);
    }
  }, [search, ratingFilter, selectedPlaceId]);

  const loadStats = useCallback(async () => {
    try {
      const response = await api.get(`${REVIEW_API}/stats`);
      setStats(response.data);
    } catch {
      // Keep list visible even if stats endpoint fails.
    }
  }, []);

  useEffect(() => {
    loadReviews();
  }, [loadReviews]);
  useEffect(() => {
    loadStats();
  }, [loadStats]);
  useEffect(() => {
    getMyPlaces()
      .then((res) => setPlaces(res.data || []))
      .catch(() => {});
  }, []);

  const filteredReviews = useMemo(() => {
    if (tabFilter === "replied")
      return reviews.filter((r) => r.replies?.length > 0);
    if (tabFilter === "unreplied")
      return reviews.filter((r) => !r.replies?.length);
    return reviews;
  }, [reviews, tabFilter]);

  const unrepliedCount = useMemo(
    () => reviews.filter((r) => !r.replies?.length).length,
    [reviews],
  );

  const handleTabChange = (nextTab) => {
    startTransition(() => {
      setTabFilter(nextTab);
    });
  };

  const handleReply = async () => {
    if (!replyContent.trim()) {
      toast.error("Nội dung phản hồi không được trống");
      return;
    }
    setSending(true);
    try {
      await api.post(`${REVIEW_API}/${replyingTo}/reply`, {
        content: replyContent,
      });
      toast.success("Phản hồi thành công");
      setReplyingTo(null);
      setReplyContent("");
      await loadReviews();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể phản hồi");
    } finally {
      setSending(false);
    }
  };

  const handleStartEditReply = (reply) => {
    setEditingReplyId(reply.id);
    setEditContent(reply.content || "");
  };

  const handleCancelEditReply = () => {
    setEditingReplyId(null);
    setEditContent("");
  };

  const handleSaveEditReply = async (reviewId, replyId) => {
    if (!editContent.trim()) {
      toast.error("Nội dung phản hồi không được trống");
      return;
    }

    setActionLoadingByReply((prev) => ({ ...prev, [replyId]: true }));
    try {
      await api.put(`${REVIEW_API}/${reviewId}/replies/${replyId}`, {
        content: editContent,
      });
      toast.success("Cập nhật phản hồi thành công");
      handleCancelEditReply();
      await loadReviews();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể cập nhật phản hồi");
    } finally {
      setActionLoadingByReply((prev) => ({ ...prev, [replyId]: false }));
    }
  };

  const handleDeleteReply = async (reviewId, replyId) => {
    setActionLoadingByReply((prev) => ({ ...prev, [replyId]: true }));
    try {
      await api.delete(`${REVIEW_API}/${reviewId}/replies/${replyId}`);
      toast.success("Xóa phản hồi thành công");
      if (editingReplyId === replyId) {
        handleCancelEditReply();
      }
      await loadReviews();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể xóa phản hồi");
    } finally {
      setActionLoadingByReply((prev) => ({ ...prev, [replyId]: false }));
    }
  };

  const handleModerateReply = async (reviewId, replyId, status) => {
    setActionLoadingByReply((prev) => ({ ...prev, [replyId]: true }));
    try {
      await api.patch(
        `${REVIEW_API}/${reviewId}/replies/${replyId}/moderation`,
        {
          status,
        },
      );
      toast.success(
        status === "hidden" ? "Đã ẩn phản hồi" : "Đã hiển thị phản hồi",
      );
      await loadReviews();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể moderation phản hồi");
    } finally {
      setActionLoadingByReply((prev) => ({ ...prev, [replyId]: false }));
    }
  };

  return (
    <div className="space-y-6 p-6 lg:p-8 min-h-screen">
      {/* Header */}
      <PageHeader
        title="Quản lý đánh giá"
        subtitle="Xem và phản hồi đánh giá từ khách hàng"
        badge={stats?.total || undefined}
      />

      {/* Stats Overview */}
      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {/* Average rating */}
          <SectionCard>
            <div className="flex flex-col items-center justify-center py-4 gap-2">
              <p className="text-5xl font-bold text-foreground">
                {Number(stats.avgRating || 0).toFixed(1)}
              </p>
              <StarRating rating={Math.round(stats.avgRating)} size="lg" />
              <p className="text-xs text-muted-foreground">
                Trung bình từ {stats.total} đánh giá
              </p>
            </div>
          </SectionCard>

          {/* Rating distribution */}
          <SectionCard title="Phân bố xếp hạng" className="md:col-span-2">
            <div className="space-y-2.5">
              {[5, 4, 3, 2, 1].map((r) => (
                <RatingBar
                  key={r}
                  star={r}
                  count={stats.byRating?.[r] || 0}
                  total={stats.total || 0}
                />
              ))}
            </div>
          </SectionCard>
        </div>
      )}

      {/* Main List */}
      <SectionCard
        title="Danh sách đánh giá"
        titleIcon={MessagesSquare}
        bodyClassName="p-0"
        action={
          <div className="flex gap-2 items-center">
            <Select value={selectedPlaceId} onValueChange={setSelectedPlaceId}>
              <SelectTrigger className="h-8 text-xs w-40">
                <SelectValue placeholder="Tất cả địa điểm" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Tất cả địa điểm</SelectItem>
                {places.map((p) => (
                  <SelectItem key={p.id} value={String(p.id)}>
                    {p.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Select value={ratingFilter} onValueChange={setRatingFilter}>
              <SelectTrigger className="h-8 text-xs w-28">
                <SelectValue placeholder="Tất cả sao" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="0">Tất cả sao</SelectItem>
                {[5, 4, 3, 2, 1].map((r) => (
                  <SelectItem key={r} value={String(r)}>
                    {r} sao
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground pointer-events-none" />
              <Input
                placeholder="Tìm nội dung..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-8 h-8 text-xs w-40"
              />
            </div>
          </div>
        }
      >
        <Tabs value={tabFilter} onValueChange={handleTabChange}>
          <div className="px-5 border-b border-border/60">
            <TabsList className="h-10 bg-transparent gap-1 p-0">
              <TabsTrigger value="all" className={DESIGN.tabUnderlineTrigger}>
                Tất cả ({reviews.length})
              </TabsTrigger>
              <TabsTrigger
                value="unreplied"
                className={DESIGN.tabUnderlineTrigger}
              >
                Chưa phản hồi ({unrepliedCount})
              </TabsTrigger>
              <TabsTrigger
                value="replied"
                className={DESIGN.tabUnderlineTrigger}
              >
                Đã phản hồi ({reviews.length - unrepliedCount})
              </TabsTrigger>
            </TabsList>
            {isPendingTransition && (
              <p className="py-1 text-[11px] text-muted-foreground">
                Đang lọc đánh giá...
              </p>
            )}
          </div>

          {["all", "unreplied", "replied"].map((tab) => (
            <TabsContent key={tab} value={tab} className="mt-0">
              <div className="p-5">
                {loading ? (
                  <div className="space-y-4">
                    {Array.from({ length: 3 }).map((_, i) => (
                      <div
                        key={i}
                        className="space-y-2 p-4 rounded-xl border border-border"
                      >
                        <div className="flex items-center gap-2">
                          <Skeleton className="h-9 w-9 rounded-full" />
                          <div className="space-y-1.5">
                            <Skeleton className="h-3.5 w-32" />
                            <Skeleton className="h-3 w-24" />
                          </div>
                        </div>
                        <Skeleton className="h-3.5 w-full" />
                        <Skeleton className="h-3.5 w-3/4" />
                      </div>
                    ))}
                  </div>
                ) : filteredReviews.length === 0 ? (
                  <EmptyState icon={Star} message="Không có đánh giá nào." />
                ) : (
                  <div className="space-y-4">
                    {filteredReviews.map((review) => (
                      <ReviewCard
                        key={review.id}
                        review={review}
                        replyingTo={replyingTo}
                        replyContent={replyContent}
                        editingReplyId={editingReplyId}
                        editContent={editContent}
                        sending={sending}
                        actionLoadingByReply={actionLoadingByReply}
                        onStartReply={setReplyingTo}
                        onCancelReply={() => {
                          setReplyingTo(null);
                          setReplyContent("");
                        }}
                        onContentChange={setReplyContent}
                        onSendReply={handleReply}
                        onStartEditReply={handleStartEditReply}
                        onCancelEditReply={handleCancelEditReply}
                        onEditContentChange={setEditContent}
                        onSaveEditReply={(replyId) =>
                          handleSaveEditReply(review.id, replyId)
                        }
                        onDeleteReply={(replyId) =>
                          handleDeleteReply(review.id, replyId)
                        }
                        onModerateReply={(replyId, status) =>
                          handleModerateReply(review.id, replyId, status)
                        }
                      />
                    ))}
                  </div>
                )}
              </div>
            </TabsContent>
          ))}
        </Tabs>
      </SectionCard>
    </div>
  );
};

