            <div className="space-y-1.5">
              <Label htmlFor="vc-end">Ngày kết thúc</Label>
              <Input
                id="vc-end"
                type="date"
                value={form.endDate}
                onChange={(e) => setForm({ ...form, endDate: e.target.value })}
